from agent import *from models.products import *import simplejsondef run(context, session):    session.queue(Request('https://colomerandsons.com/categoria-producto/relojes/'), process_prodlist, dict(cat='Relojes'))def process_prodlist(data, context, session):    prods = data.xpath('//ul/li[contains(@class, "type-product")]')    for prod in prods:        name = prod.xpath('.//h3[contains(@class, "product_title")]//text()').string()        url = prod.xpath('.//div[contains(@class, "product_title")]//a/@href').string()        ssid = prod.xpath('@data-pid').string()        session.queue(Request(url+'?clang=es'), process_product, dict(context, name=name, url=url, ssid=ssid))def process_product(data, context, session):    product = Product()    product.name = context['name']    product.url = context['url']    product.category = context['cat']    product.ssid = context['ssid']    prod_json = data.xpath("""//script[contains(., '"@type":"Product"')]/text()""").string()    if prod_json:        prod_json = simplejson.loads(prod_json)        mpn = prod_json.get('sku')        if mpn:            product.properties.append(ProductProperty(type='id.manufacturer', value=mpn))    revs = data.xpath('//ol[@class="commentlist"]/li/div')    for rev in revs:        review = Review()        review.type = 'user'        review.url = product.url        review.ssid = rev.xpath('@id').string().split('-')[-1]        date = rev.xpath('.//time/@datetime').string()        if date:            review.date = date.split('T')[0]        author = rev.xpath('.//p/strong[contains(@class, "review__author")]/text()').string()        if author:            review.authors.append(Person(name=author, ssid=author))        is_verified = rev.xpath('.//p/em[contains(@class, "verified")]')        if is_verified:            review.add_property(type='is_verified_buyer', value=True)        grade_overall = rev.xpath('.//span/strong[@class="rating"]/text()').string()        if grade_overall:            review.grades.append(Grade(type="overall", value=float(grade_overall), best=5.0))        excerpt = rev.xpath('.//div[@class="description"]/p/text()').string(multiple=True)        if excerpt:            review.properties.append(ReviewProperty(type="excerpt", value=excerpt))            product.reviews.append(review)    if product.reviews:        session.emit(product)    # Loaded all revs